{"script": "import os
import json
import csv
import re
from collections import defaultdict


def load_json(path):
    with open(path, 'r', encoding='utf-8') as f:
        return json.load(f)


def get_bbox(word):
    for key in ('bbox', 'bounding_box', 'boundingBox', 'box'):
        if key in word:
            return word[key]
    return None


def normalize_bbox(bbox):
    if isinstance(bbox, dict):
        if 'x0' in bbox:
            return [bbox['x0'], bbox['y0'], bbox['x1'], bbox['y1']]
        if 'left' in bbox:
            return [bbox['left'], bbox['top'], bbox['left'] + bbox.get('width', 0), bbox['top'] + bbox.get('height', 0)]
        if 'x' in bbox:
            return [bbox['x'], bbox['y'], bbox['x'] + bbox.get('w', 0), bbox['y'] + bbox.get('h', 0)]
    if isinstance(bbox, (list, tuple)) and len(bbox) >= 4:
        return [bbox[0], bbox[1], bbox[2], bbox[3]]
    return None


def get_text(word):
    for key in ('text', 'content', 'word', 'value'):
        if key in word:
            return str(word[key])
    return ''


def main():
    input_path = os.environ['ORIGINAL_WORDS_JSON']
    cells_csv = os.environ['OUTPUT_CELLS_CSV']
    metrics_csv = os.environ['OUTPUT_METRICS_CSV']
    audit_json = os.environ['OUTPUT_AUDIT_JSON']
    summary_md = os.environ['SUMMARY_MD']

    data = load_json(input_path)

    # Extract table bbox and words
    table_bbox = None
    words = []

    if isinstance(data, dict):
        for key in ('table_bbox', 'table_bounding_box', 'tableBoundingBox'):
            if key in data:
                table_bbox = normalize_bbox(data[key])
                break
        for key in ('words', 'tokens', 'page_words', 'word_list'):
            if key in data and isinstance(data[key], list):
                words = data[key]
                break
        if not words and 'pages' in data:
            for page in data['pages']:
                if isinstance(page, dict):
                    for key in ('words', 'tokens'):
                        if key in page:
                            words.extend(page[key])
    elif isinstance(data, list):
        words = data

    # Parse word bboxes
    parsed_words = []
    for w in words:
        bbox = get_bbox(w)
        if bbox is None:
            continue
        bbox = normalize_bbox(bbox)
        if bbox is None:
            continue
        text = get_text(w)
        if not text:
            continue
        x_center = (bbox[0] + bbox[2]) / 2.0
        y_center = (bbox[1] + bbox[3]) / 2.0
        width = bbox[2] - bbox[0]
        height = bbox[3] - bbox[1]
        parsed_words.append({
            'text': text,
            'bbox': bbox,
            'x_center': x_center,
            'y_center': y_center,
            'width': width,
            'height': height
        })

    # Filter words inside table bbox
    table_words = []
    if table_bbox:
        for pw in parsed_words:
            if (pw['bbox'][0] >= table_bbox[0] - 2 and
                    pw['bbox'][1] >= table_bbox[1] - 2 and
                    pw['bbox'][2] <= table_bbox[2] + 2 and
                    pw['bbox'][3] <= table_bbox[3] + 2):
                table_words.append(pw)
    else:
        table_words = parsed_words

    if not table_words:
        table_words = parsed_words

    # Sort by y_center then x_center
    table_words.sort(key=lambda w: (w['y_center'], w['x_center']))

    # Row grouping
    if table_words:
        heights = [w['height'] for w in table_words if w['height'] > 0]
        median_height = sorted(heights)[len(heights) // 2] if heights else 10
    else:
        median_height = 10

    row_tolerance = median_height * 0.6

    rows = []
    for pw in table_words:
        placed = False
        for row in rows:
            if abs(pw['y_center'] - row['center']) < row_tolerance:
                row['words'].append(pw)
                row['center'] = sum(w['y_center'] for w in row['words']) / len(row['words'])
                placed = True
                break
        if not placed:
            rows.append({'center': pw['y_center'], 'words': [pw]})

    rows.sort(key=lambda r: r['center'])

    # Column inference from x clusters
    all_x_centers = [w['x_center'] for w in table_words]
    if all_x_centers:
        all_x_centers.sort()
        # Cluster x centers
        col_clusters = []
        cluster = [all_x_centers[0]]
        for x in all_x_centers[1:]:
            if x - cluster[-1] > median_height * 1.5:
                col_clusters.append(cluster)
                cluster = [x]
            else:
                cluster.append(x)
        col_clusters.append(cluster)

        col_bands = []
        for cluster in col_clusters:
            col_bands.append((min(cluster), max(cluster)))

        # Merge overlapping/adjacent bands
        merged_bands = []
        for band in col_bands:
            if merged_bands and band[0] <= merged_bands[-1][1] + median_height:
                merged_bands[-1] = (merged_bands[-1][0], max(merged_bands[-1][1], band[1]))
            else:
                merged_bands.append(band)
        col_bands = merged_bands
    else:
        col_bands = []

    # Assign words to columns
    def assign_column(x_center):
        best_col = None
        best_overlap = 0
        for i, (x0, x1) in enumerate(col_bands):
            if x0 <= x_center <= x1:
                return i
            # Check overlap with word width
        # Fallback: nearest column
        if col_bands:
            min_dist = float('inf')
            for i, (x0, x1) in enumerate(col_bands):
                dist = min(abs(x_center - x0), abs(x_center - x1))
                if dist < min_dist:
                    min_dist = dist
                    best_col = i
        return best_col

    # Build cells
    cells = []
    for row_idx, row in enumerate(rows):
        row_words = sorted(row['words'], key=lambda w: w['x_center'])
        col_buckets = defaultdict(list)
        for pw in row_words:
            col_idx = assign_column(pw['x_center'])
            if col_idx is None:
                col_idx = 0
            col_buckets[col_idx].append(pw)

        for col_idx, bucket in sorted(col_buckets.items()):
            bucket.sort(key=lambda w: w['x_center'])
            text = ' '.join(w['text'] for w in bucket)
            is_header = 1 if row_idx == 0 else 0
            cells.append({
                'row_id': row_idx,
                'col_id': col_idx,
                'row_span': 1,
                'col_span': 1,
                'is_header': is_header,
                'text': text
            })

    # Write cells CSV
    os.makedirs(os.path.dirname(cells_csv), exist_ok=True)
    with open(cells_csv, 'w', encoding='utf-8', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=['row_id', 'col_id', 'row_span', 'col_span', 'is_header', 'text'])
        writer.writeheader()
        for cell in cells:
            writer.writerow(cell)

    # Normalize metric rows
    # Identify header row to map columns
    header_cells = [c for c in cells if c['is_header'] == 1]
    header_map = {}
    for hc in header_cells:
        text_lower = hc['text'].lower().strip()
        if 'method' in text_lower:
            header_map['method'] = hc['col_id']
        elif 'dataset' in text_lower:
            header_map['dataset'] = hc['col_id']
        elif 'accuracy' in text_lower or 'acc' == text_lower:
            header_map['accuracy'] = hc['col_id']
        elif 'f1' in text_lower:
            header_map['f1'] = hc['col_id']
        elif 'note' in text_lower:
            header_map['notes'] = hc['col_id']

    # If no header detected, try to infer from first row text
    if not header_map and cells:
        first_row_cells = [c for c in cells if c['row_id'] == 0]
        first_row_cells.sort(key=lambda c: c['col_id'])
        for i, hc in enumerate(first_row_cells):
            text_lower = hc['text'].lower().strip()
            if 'method' in text_lower:
                header_map['method'] = hc['col_id']
            elif 'dataset' in text_lower:
                header_map['dataset'] = hc['col_id']
            elif 'accuracy' in text_lower or 'acc' in text_lower:
                header_map['accuracy'] = hc['col_id']
            elif 'f1' in text_lower:
                header_map['f1'] = hc['col_id']
            elif 'note' in text_lower:
                header_map['notes'] = hc['col_id']

    # Build metric rows from body cells
    body_rows = sorted(set(c['row_id'] for c in cells if c['is_header'] == 0))
    metrics = []
    issues = []

    for row_id in body_rows:
        row_cells = [c for c in cells if c['row_id'] == row_id]
        cell_by_col = {c['col_id']: c['text'] for c in row_cells}

        method = cell_by_col.get(header_map.get('method'), '') if 'method' in header_map else ''
        dataset = cell_by_col.get(header_map.get('dataset'), '') if 'dataset' in header_map else ''
        accuracy = cell_by_col.get(header_map.get('accuracy'), '') if 'accuracy' in header_map else ''
        f1 = cell_by_col.get(header_map.get('f1'), '') if 'f1' in header_map else ''
        notes = cell_by_col.get(header_map.get('notes'), '') if 'notes' in header_map else ''

        # Skip rows that look like caption/footnote or are empty
        if not method and not dataset and not accuracy and not f1:
            continue

        # Skip rows where method/dataset look like non-data text
        combined = (method + ' ' + dataset).lower()
        skip_keywords = ['table', 'caption', 'footnote', 'note:', 'figure', 'results show']
        if any(kw in combined for kw in skip_keywords) and not accuracy and not f1:
            continue

        # Clean numeric values
        def clean_numeric(val):
            if not val:
                return ''
            val = val.strip()
            val = re.sub(r'[^0-9.\-]', '', val)
            try:
                return str(float(val))
            except (ValueError, TypeError):
                return val

        accuracy_clean = clean_numeric(accuracy)
        f1_clean = clean_numeric(f1)

        # Validate
        if accuracy and not accuracy_clean:
            issues.append(f'Row {row_id}: accuracy value "{accuracy}" is non-numeric')
        if f1 and not f1_clean:
            issues.append(f'Row {row_id}: f1 value "{f1}" is non-numeric')
        if not method:
            issues.append(f'Row {row_id}: missing method')
        if not dataset:
            issues.append(f'Row {row_id}: missing dataset')

        metrics.append({
            'method': method.strip(),
            'dataset': dataset.strip(),
            'accuracy': accuracy_clean,
            'f1': f1_clean,
            'notes': notes.strip()
        })

    # If no header mapping worked, try heuristic: parse each body row by position
    if not metrics and body_rows:
        for row_id in body_rows:
            row_cells = [c for c in cells if c['row_id'] == row_id]
            row_cells.sort(key=lambda c: c['col_id'])
            texts = [c['text'].strip() for c in row_cells]
            if len(texts) >= 4:
                method = texts[0]
                dataset = texts[1]
                accuracy = texts[2]
                f1 = texts[3]
                notes = texts[4] if len(texts) > 4 else ''

                combined = (method + ' ' + dataset).lower()
                skip_keywords = ['table', 'caption', 'footnote', 'note:', 'figure']
                if any(kw in combined for kw in skip_keywords):
                    continue
                if not method and not dataset:
                    continue

                def clean_numeric(val):
                    if not val:
                        return ''
                    val = val.strip()
                    val = re.sub(r'[^0-9.\-]', '', val)
                    try:
                        return str(float(val))
                    except (ValueError, TypeError):
                        return val

                metrics.append({
                    'method': method,
                    'dataset': dataset,
                    'accuracy': clean_numeric(accuracy),
                    'f1': clean_numeric(f1),
                    'notes': notes
                })

    # Write metrics CSV
    os.makedirs(os.path.dirname(metrics_csv), exist_ok=True)
    with open(metrics_csv, 'w', encoding='utf-8', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=['method', 'dataset', 'accuracy', 'f1', 'notes'])
        writer.writeheader()
        for m in metrics:
            writer.writerow(m)

    # Audit
    best_by_dataset = {}
    for m in metrics:
        ds = m['dataset']
        if not ds:
            continue
        try:
            f1_val = float(m['f1']) if m['f1'] else 0
        except (ValueError, TypeError):
            f1_val = 0
            issues.append(f'Method {m["method"]} on {ds}: f1 value "{m["f1"]}" is non-numeric')
        if ds not in best_by_dataset or f1_val > best_by_dataset[ds]['f1']:
            best_by_dataset[ds] = {
                'method': m['method'],
                'f1': f1_val,
                'accuracy': m['accuracy']
            }

    # Check for missing fields
    for i, m in enumerate(metrics):
        for field in ['method', 'dataset', 'accuracy', 'f1']:
            if not m[field]:
                issues.append(f'Metric row {i}: missing {field}')

    if not metrics:
        issues.append('No metric rows extracted')

    audit = {
        'row_count': len(metrics),
        'best_by_dataset': best_by_dataset,
        'issues': issues
    }

    os.makedirs(os.path.dirname(audit_json), exist_ok=True)
    with open(audit_json, 'w', encoding='utf-8') as f:
        json.dump(audit, f, indent=2, ensure_ascii=False)

    # Summary Markdown
    summary_lines = []
    summary_lines.append('# PubTables Extraction Summary')
    summary_lines.append('')
    summary_lines.append('- **Source**: PubTables-style OCR word JSON with bounding boxes')
    summary_lines.append(f'- **Reconstructed cells**: {len(cells)} non-empty cells across {len(rows)} rows')
    summary_lines.append(f'- **Normalized metric rows**: {len(metrics)}')
    summary_lines.append('')
    summary_lines.append('## Best Method by Dataset (F1)')
    if best_by_dataset:
        for ds, info in sorted(best_by_dataset.items()):
            summary_lines.append(f'- **{ds}**: {info["method"]} (F1={info["f1"]})')
    else:
        summary_lines.append('- No best method determined')
    summary_lines.append('')
    summary_lines.append('## Audit Status')
    if issues:
        summary_lines.append(f'- {len(issues)} issue(s) found:')
        for issue in issues:
            summary_lines.append(f'  - {issue}')
    else:
        summary_lines.append('- No issues detected')
    summary_lines.append('')
    summary_lines.append('## Limitations')
    summary_lines.append('- Row and column reconstruction relies on bounding box geometry; minor misalignments possible')
    summary_lines.append('- Caption and footnote words outside the table bounding box are excluded from metric rows')
    summary_lines.append('- Numeric normalization strips non-numeric characters; values are not cross-checked against external sources')
